-- ========================================
-- 0. Create missing support tables
-- ========================================

CREATE TABLE IF NOT EXISTS ssp_ports_protocols (id TEXT PRIMARY KEY, ssp_id TEXT NOT NULL, port TEXT NOT NULL, protocol TEXT, service TEXT, purpose TEXT, direction TEXT CHECK (direction IN ('Inbound','Outbound','Internal','Bidirectional')), dit_ref TEXT, created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (ssp_id) REFERENCES ssp_documents(id) ON DELETE CASCADE);

CREATE TABLE IF NOT EXISTS poam_milestones (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), poam_id TEXT NOT NULL REFERENCES poams(id) ON DELETE CASCADE, title TEXT NOT NULL, target_date TEXT, status TEXT DEFAULT 'pending' CHECK (status IN ('pending','in_progress','completed')), completion_date TEXT, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')));

CREATE TABLE IF NOT EXISTS vulnerability_definitions (id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))), cve_id TEXT UNIQUE, title TEXT NOT NULL, description TEXT, cvss_score REAL, cvss_vector TEXT, severity TEXT DEFAULT 'medium' CHECK (severity IN ('critical','high','medium','low','info')), affected_products TEXT DEFAULT '[]', references_list TEXT DEFAULT '[]', published_at TEXT, modified_at TEXT, exploit_available INTEGER DEFAULT 0, patch_available INTEGER DEFAULT 0, created_at TEXT DEFAULT (datetime('now')));


