INSERT OR IGNORE INTO vulnerability_definitions (id, cve_id, title, description, cvss_score, cvss_vector, severity, affected_products, references_list, published_at, exploit_available, patch_available, created_at) VALUES ('vdef-001', 'CVE-2021-44228', 'Apache Log4j Remote Code Execution (Log4Shell)', 'Apache Log4j2 2.0-beta9 through 2.15.0 JNDI features do not protect against attacker-controlled LDAP and other endpoints, allowing RCE.', 10, 'CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:C/C:H/I:H/A:H', 'critical', '["Apache Log4j 2.x"]', '["https://nvd.nist.gov/vuln/detail/CVE-2021-44228"]', '2021-12-10', 1, 1, '2026-02-18 06:00:00');
INSERT OR IGNORE INTO vulnerability_definitions (id, cve_id, title, description, cvss_score, cvss_vector, severity, affected_products, references_list, published_at, exploit_available, patch_available, created_at) VALUES ('vdef-002', 'CVE-2022-22965', 'Spring Framework RCE (Spring4Shell)', 'Spring Framework before 5.3.18 and 5.2.20 allows RCE via data binding to a ClassLoader accessible via a crafted request.', 9.8, 'CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:H/A:H', 'critical', '["Spring Framework 5.x"]', '["https://nvd.nist.gov/vuln/detail/CVE-2022-22965"]', '2022-03-31', 1, 1, '2026-02-18 06:00:00');
INSERT OR IGNORE INTO vulnerability_definitions (id, cve_id, title, description, cvss_score, cvss_vector, severity, affected_products, references_list, published_at, exploit_available, patch_available, created_at) VALUES ('vdef-003', 'CVE-2023-34362', 'MOVEit Transfer SQL Injection', 'MOVEit Transfer web application contains a SQL injection vulnerability that could allow an unauthenticated attacker to gain access to the database.', 9.8, 'CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:H/A:H', 'critical', '["Progress MOVEit Transfer"]', '["https://nvd.nist.gov/vuln/detail/CVE-2023-34362"]', '2023-06-02', 1, 1, '2026-02-18 06:00:00');
INSERT OR IGNORE INTO vulnerability_definitions (id, cve_id, title, description, cvss_score, cvss_vector, severity, affected_products, references_list, published_at, exploit_available, patch_available, created_at) VALUES ('vdef-004', 'CVE-2024-3094', 'XZ Utils Backdoor', 'Malicious code was discovered in the upstream tarballs of xz versions 5.6.0 and 5.6.1 that could allow unauthorized remote access.', 10, 'CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:C/C:H/I:H/A:H', 'critical', '["XZ Utils 5.6.x"]', '["https://nvd.nist.gov/vuln/detail/CVE-2024-3094"]', '2024-03-29', 1, 1, '2026-02-18 06:00:00');
INSERT OR IGNORE INTO vulnerability_definitions (id, cve_id, title, description, cvss_score, cvss_vector, severity, affected_products, references_list, published_at, exploit_available, patch_available, created_at) VALUES ('vdef-005', 'CVE-2023-44487', 'HTTP/2 Rapid Reset Attack', 'The HTTP/2 protocol allows a denial of service via rapid stream resets (Rapid Reset Attack), affecting multiple web servers and proxies.', 9.1, 'CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:N/I:N/A:H', 'critical', '["NGINX","Apache httpd","Node.js"]', '["https://nvd.nist.gov/vuln/detail/CVE-2023-44487"]', '2023-10-10', 1, 1, '2026-02-18 06:00:00');
